/*
 * grow_light.ino — LED Grow Light Controller (ESP32 + WS2812B)
 *
 * Elements:
 *   1. WS2812B 60-LED strip (GPIO 13, via level-shift) — FastLED
 *   2. ESP32 WiFi + MQTT                               — broker on LAN
 *   3. DS3231 RTC (I²C 0x68, INT GPIO 34)             — schedule alarms
 *   4. SSD1306 OLED (I²C 0x3C)                        — status display
 *   5. MQTT Logger                                     — event log
 *
 * MQTT topics:
 *   growlight/cmd    — JSON {cmd:"on"|"off"|"spectrum", stage:"SEEDLING"}
 *   growlight/status — JSON {state, stage, bright_pct, next_event}
 *   growlight/events — JSON event log (retained=false)
 */

#include <Wire.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <FastLED.h>
#include <RTClib.h>
#include <Adafruit_SSD1306.h>
#include <ArduinoJson.h>

// --- Config ---
const char* SSID      = "HomeNet";
const char* WIFI_PASS = "changeme";
const char* MQTT_HOST = "192.168.1.10";
#define NUM_LEDS   60
#define LED_PIN    13
#define RTC_INT    34

// --- Photoperiod (24-h format) ---
int lights_on_hour  = 6;
int lights_off_hour = 22;   // 16-hour photoperiod

// --- Spectrum presets: {blue_pct, red_pct} ---
struct Spectrum { uint8_t r, g, b; };
const Spectrum SEEDLING  = { 50,  0, 200 };
const Spectrum VEG       = {120,  0, 180 };
const Spectrum FLOWERING = { 220, 0,  80 };

// --- State ---
bool     lights_on  = false;
Spectrum spectrum   = SEEDLING;
String   stage_name = "SEEDLING";

// --- Objects ---
CRGB            leds[NUM_LEDS];
RTC_DS3231      rtc;
Adafruit_SSD1306 oled(128, 64, &Wire, -1);
WiFiClient       wc;
PubSubClient     mqtt(wc);

volatile bool rtc_alarm = false;
void ICACHE_RAM_ATTR isr_rtc() { rtc_alarm = true; }

void set_strip(bool on) {
  lights_on = on;
  if (on) {
    for (int i = 0; i < NUM_LEDS; i++)
      leds[i] = CRGB(spectrum.r, spectrum.g, spectrum.b);
    FastLED.setBrightness(150);
  } else {
    FastLED.clear();
  }
  FastLED.show();
}

void update_oled() {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("LIGHTS: %s", lights_on ? "ON" : "OFF");
  oled.setCursor(0, 12); oled.printf("Period: %02d:00-%02d:00", lights_on_hour, lights_off_hour);
  oled.setCursor(0, 24); oled.printf("Stage: %s", stage_name.c_str());
  DateTime now = rtc.now();
  oled.setCursor(0, 36); oled.printf("Time: %02d:%02d:%02d", now.hour(), now.minute(), now.second());
  oled.display();
}

void on_mqtt(char* topic, byte* payload, unsigned int length) {
  StaticJsonDocument<128> doc;
  if (deserializeJson(doc, payload, length)) return;
  const char* cmd = doc["cmd"];
  if (!cmd) return;
  if      (strcmp(cmd, "on")  == 0) set_strip(true);
  else if (strcmp(cmd, "off") == 0) set_strip(false);
  else if (strcmp(cmd, "spectrum") == 0) {
    const char* s = doc["stage"];
    if      (s && strcmp(s, "VEG")      == 0) { spectrum = VEG;      stage_name = "VEG"; }
    else if (s && strcmp(s, "FLOWER")   == 0) { spectrum = FLOWERING; stage_name = "FLOWER"; }
    else                                       { spectrum = SEEDLING;  stage_name = "SEEDLING"; }
    if (lights_on) set_strip(true);  // reapply
  }
}

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    if (mqtt.connect("GrowLight")) mqtt.subscribe("growlight/cmd");
    else delay(3000);
  }
}

void arm_rtc_alarms() {
  rtc.clearAlarm(1); rtc.clearAlarm(2);
  rtc.setAlarm1(DateTime(2000,1,1, lights_on_hour,  0, 0), DS3231_A1_Hour);
  rtc.setAlarm2(DateTime(2000,1,1, lights_off_hour, 0, 0), DS3231_A2_Hour);
  rtc.writeSqwPinMode(DS3231_OFF);  // INT/SQW = alarm interrupt
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  FastLED.addLeds<WS2812B, LED_PIN, GRB>(leds, NUM_LEDS);
  FastLED.clear(); FastLED.show();

  rtc.begin();
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  arm_rtc_alarms();
  pinMode(RTC_INT, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(RTC_INT), isr_rtc, FALLING);

  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(500);
  mqtt.setServer(MQTT_HOST, 1883);
  mqtt.setCallback(on_mqtt);
  mqtt_reconnect();

  // Determine initial light state from RTC
  DateTime now = rtc.now();
  bool should_be_on = (now.hour() >= lights_on_hour && now.hour() < lights_off_hour);
  set_strip(should_be_on);

  Serial.println(F("Grow light ready."));
}

void loop() {
  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();

  if (rtc_alarm) {
    rtc_alarm = false;
    // Determine which alarm fired
    DateTime now = rtc.now();
    bool should_be_on = (now.hour() >= lights_on_hour && now.hour() < lights_off_hour);
    set_strip(should_be_on);
    rtc.clearAlarm(1); rtc.clearAlarm(2);
    arm_rtc_alarms();

    // Publish event
    char buf[128];
    snprintf(buf, sizeof(buf), "{\"event\":\"%s\",\"stage\":\"%s\",\"hour\":%d}",
             lights_on ? "ON" : "OFF", stage_name.c_str(), now.hour());
    mqtt.publish("growlight/events", buf);
  }

  static unsigned long last_status = 0;
  if (millis() - last_status >= 60000UL) {
    last_status = millis();
    char buf[128];
    snprintf(buf, sizeof(buf), "{\"state\":\"%s\",\"stage\":\"%s\"}",
             lights_on ? "on" : "off", stage_name.c_str());
    mqtt.publish("growlight/status", buf, true);
    update_oled();
  }

  delay(50);
}
